# ✅ Edit Distance: Spell checking, version control (diff utility) [web:208][web:212]
def edit_distance(word1, word2):
    n, m = len(word1), len(word2)
    dp = [[0] * (m + 1) for _ in range(n + 1)]

    # Initialize base cases
    for i in range(n + 1):
        dp[i][0] = i  # ✅ Delete all
    for j in range(m + 1):
        dp[0][j] = j  # ✅ Insert all

    for i in range(1, n + 1):
        for j in range(1, m + 1):
            if word1[i - 1] == word2[j - 1]:
                dp[i][j] = dp[i - 1][j - 1]  # ✅ No operation
            else:
                dp[i][j] = 1 + min(
                    dp[i - 1][j],  # ✅ Delete
                    dp[i][j - 1],  # ✅ Insert
                    dp[i - 1][j - 1]  # ✅ Replace
                )

    return dp[n][m]  # ✅ Edit distance [web:208][web:212]

