# ✅ Coin Change: Greedy fails for non-canonical coins, DP works [web:208]
def coin_change(coins, amount):
    dp = [amount + 1] * (amount + 1)  # ✅ Initialize with max
    dp[0] = 0  # ✅ Base case

    for coin in coins:
        for a in range(coin, amount + 1):
            dp[a] = min(dp[a], dp[a - coin] + 1)  # ✅ Min coins [web:208]

    return dp[amount] if dp[amount] <= amount else -1  # ✅ Result [web:208]

